import pika
import json
import time
import sys
from datetime import datetime

class SecureRabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, username='guest', password='guest', queue_name='task_queue'):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        credentials = pika.PlainCredentials(self.username, self.password)
        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            credentials=credentials,
            heartbeat=600,
            blocked_connection_timeout=300
        )
        self.connection = pika.BlockingConnection(parameters)
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_task(self, task_data):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        message = json.dumps(task_data)
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type='application/json'
            )
        )
        print(f"[x] Sent task: {task_data}")
        
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


class SecureRabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, username='guest', password='guest', queue_name='task_queue'):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        credentials = pika.PlainCredentials(self.username, self.password)
        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            credentials=credentials,
            heartbeat=600,
            blocked_connection_timeout=300
        )
        self.connection = pika.BlockingConnection(parameters)
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_task(self, task_data):
        print(f"[x] Processing task: {task_data}")
        time.sleep(task_data.get('duration', 1))
        print(f"[x] Task completed: {task_data}")
        
    def callback(self, ch, method, properties, body):
        try:
            task_data = json.loads(body)
            self.process_task(task_data)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"[!] Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            
    def start_consuming(self):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        print(f'[*] Waiting for messages in queue: {self.queue_name}. To exit press CTRL+C')
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            print('[*] Stopping consumer...')
            self.channel.stop_consuming()
            
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


